import React from 'react';
import { Link } from 'react-router-dom';
import { Product } from '../types';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHeart as faSolidHeart, faHeart as faRegularHeart, faStar as faSolidStar, faStarHalfAlt, faStar as faRegularStar } from '@fortawesome/free-solid-svg-icons';
import { IconDefinition } from '@fortawesome/free-brands-svg-icons';

interface ProductCardProps {
  product: Product;
  isFavorite: boolean;
  onFavoriteToggle: (id: number) => void;
  categoryIcon: { icon: IconDefinition; color: string };
  cardWidthPx?: number;
  linkTo?: string;
}

const ProductCard: React.FC<ProductCardProps> = ({
  product,
  isFavorite,
  onFavoriteToggle,
  categoryIcon,
  cardWidthPx,
  linkTo
}) => {
  return (
    <Link
      to={linkTo || `/products/${product.id}`}
      className="relative bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300 flex-1 cursor-pointer group"
      style={cardWidthPx ? { minWidth: `${cardWidthPx}px`, maxWidth: `${cardWidthPx}px` } : {}}
    >
      {/* 즐겨찾기 버튼 */}
      <button
        className="absolute top-4 right-4 z-10"
        onClick={e => { e.preventDefault(); onFavoriteToggle(product.id); }}
      >
        <FontAwesomeIcon
          icon={isFavorite ? faSolidHeart : faRegularHeart}
          className={`text-2xl ${isFavorite ? 'text-red-500' : 'text-gray-300'}`}
        />
      </button>
      {/* 카드 상품 이미지 */}
      <div
        className="flex justify-center items-center h-40 p-6 bg-cover bg-center transition-transform duration-300 group-hover:scale-110"
        style={{
          backgroundImage: product.background ? `url(${product.background})` : undefined,
          backgroundColor: !product.background ? '#FFF7ED' : undefined
        }}
      >
        <FontAwesomeIcon
          icon={categoryIcon.icon}
          className={`text-5xl ${categoryIcon.color}`}
        />
      </div>
      {/* 카드 내용 */}
      <div className="p-4">
        <h3 className="font-semibold text-gray-900 mb-1">{product.name}</h3>
        <p className="text-gray-500 text-sm mb-2 truncate">{product.description}</p>
        <div className="flex items-center mb-2">
          {product.discountRate && (
            <span className="text-blue-600 font-bold text-lg mr-2">{product.discountRate}%</span>
          )}
          {product.originalPrice && (
            <span className="text-gray-400 line-through text-sm mr-2">{product.originalPrice.toLocaleString()}원</span>
          )}
          <span className="text-gray-900 font-bold text-sm">{typeof product.price === 'number' ? product.price.toLocaleString() : product.price}원</span>
        </div>
        <div className="flex items-center">
          {/* 별점 표시 */}
          {(() => {
            const stars = [];
            const rating = product.rating ?? 0;
            for (let i = 1; i <= 5; i++) {
              if (rating >= i) {
                stars.push(<FontAwesomeIcon key={i} icon={faSolidStar} className="text-yellow-400" />);
              } else if (rating >= i - 0.5) {
                stars.push(<FontAwesomeIcon key={i} icon={faStarHalfAlt} className="text-yellow-400" />);
              } else {
                stars.push(<FontAwesomeIcon key={i} icon={faRegularStar} className="text-gray-300" />);
              }
            }
            return stars;
          })()}
          <span className="text-gray-700 font-medium ml-2 mr-1 text-sm">{product.rating?.toFixed(1)}</span>
          <span className="text-gray-400 text-xs">({product.reviewCount?.toLocaleString()})</span>
        </div>
      </div>
    </Link>
  );
};

export default ProductCard;
